const raw = $input.first().json;

let data = raw.body ?? raw;
if (typeof data === 'string') {
  try { data = JSON.parse(data); } catch(e) { throw new Error('Invalid JSON body: ' + e.message); }
}

let body = data.test_cases ? data.test_cases[0].body : data;
if (typeof body === 'string') {
  try { body = JSON.parse(body); } catch(e) {}
}

if (!body.student_id)       throw new Error('Missing: student_id');
if (!body.mastery_profile)  throw new Error('Missing: mastery_profile');
if (!Array.isArray(body.mastery_profile.knowledge_gaps)) throw new Error('knowledge_gaps must be an array');
if (body.mastery_profile.knowledge_gaps.length === 0)    throw new Error('No knowledge gaps found');

return [{
  json: {
    student_id:            String(body.student_id),
    analysis_timestamp:    body.analysis_timestamp || new Date().toISOString(),
    overall_mastery_score: body.mastery_profile.overall_mastery_score ?? null,
    knowledge_gaps:        body.mastery_profile.knowledge_gaps,
    strengths:             body.mastery_profile.strengths    || [],
    recommendations:       body.recommendations              || {},
    data_sources:          body.data_sources                 || {}
  }
}];

const data = $input.first().json;

const DIFFICULTY_MAP = {
  'FUNDAMENTAL_GAP': 'beginner',
  'PARTIAL_GAP':     'intermediate',
  'SURFACE_GAP':     'intermediate'
};
const CONTENT_TYPE_MAP = {
  'interactive_tutorial':  ['concept_explanation','step_by_step_tutorial','coding_examples'],
