  'targeted_quiz':         ['concept_summary','quiz','practice_exercises'],
  'practice_exercises':    ['practice_exercises','coding_examples','quiz']
};

const studentId    = String(data.student_id);
const masteryScore = data.overall_mastery_score ?? null;

const processedGaps = data.knowledge_gaps.map((gap, index) => {
  const intervention        = gap.suggested_intervention || {};
  const primaryIntervention = intervention.primary || 'interactive_tutorial';
  const contentTypes        = CONTENT_TYPE_MAP[primaryIntervention] || ['concept_explanation','practice_exercises'];
  return {
    student_id:            studentId,
    overall_mastery_score: masteryScore,
    priority:              index + 1,
    topic:                 gap.topic,
    topic_id:              gap.topic_id,
    gap_type:              gap.gap_type,
    difficulty_level:      DIFFICULTY_MAP[gap.gap_type] || intervention.difficulty_level || 'beginner',
    misconceptions:        gap.misconceptions           || [],
    error_patterns:        gap.observed_error_patterns  || {},
    evidence_summary:      gap.evidence_summary         || '',
    prerequisite_topics:   gap.prerequisite_topics      || [],
    related_topics:        gap.related_topics           || [],
    learning_objectives:   intervention.learning_objectives || [],
    content_types_to_generate: contentTypes,
    estimated_time_minutes: intervention.estimated_time_minutes || 60,
    primary_intervention:  primaryIntervention
  };
});

return [{
  json: {
    student_id:            studentId,
    analysis_timestamp:    data.analysis_timestamp,
    overall_mastery_score: masteryScore,
    strengths:             data.strengths,
    processed_gaps:        processedGaps,
    recommendations:       data.recommendations,
    processing_timestamp:  new Date().toISOString()
  }
}];

const item = $json;
const gap  = item.gap || item;

