const item     = $input.first().json;
const upstream = $('Prompt Construction Module').first().json;

const raw = (item.message?.content || item.response || '').trim();

function stripFences(s) {
  return s.replace(/^```json\s*/gi, '').replace(/^```\s*/gi, '').replace(/\s*```$/gi, '').replace(/^`+/g, '').replace(/`+$/g, '').trim();
}

function findOutermostObject(s) {
  const start = s.indexOf('{');
  if (start === -1) return null;
  let depth = 0;
  for (let i = start; i < s.length; i++) {
    if (s[i] === '{') depth++;
    else if (s[i] === '}') { depth--; if (depth === 0) return s.substring(start, i + 1); }
  }
  const lastClose = s.lastIndexOf('}');
  if (lastClose > start) return s.substring(start, lastClose + 1);
  return null;
}

function extractField(s, fieldName, type) {
  if (type === 'string') {
    const re = new RegExp('"' + fieldName + '"\\s*:\\s*"((?:[^"\\\\]|\\\\.)*)"', 's');
    const m = s.match(re);
    return m ? m[1].replace(/\\n/g,'\n').replace(/\\"/g,'"') : null;
  }
  const bracket = type === 'array' ? '[' : '{';
  const closeBracket = type === 'array' ? ']' : '}';
  const re = new RegExp('"' + fieldName + '"\\s*:\\s*(\\' + bracket + ')');
  const m = re.exec(s);
  if (!m) return null;
  let start = m.index + m[0].length - 1;
  let depth = 0;
  for (let i = start; i < s.length; i++) {
    if (s[i] === bracket) depth++;
    else if (s[i] === closeBracket) { depth--; if (depth === 0) { try { return JSON.parse(s.substring(start, i+1)); } catch(e) { return null; } } }
  }
  return null;
}

let llmContent = null;
let parseError  = null;
const cleaned   = stripFences(raw);
const candidate = findOutermostObject(cleaned);

if (candidate) {
  try {
    llmContent = JSON.parse(candidate);
  } catch(e) {
    parseError = 'JSON.parse failed: ' + e.message;
    const partial = {};
    ['page_title'].forEach(f => { partial[f] = extractField(candidate, f, 'string'); });
    ['introduction','concept_explained','syntax_reference','examples','step_by_step_guide','debugging_exercise','quick_reference','connections'].forEach(f => { partial[f] = extractField(candidate, f, 'object'); });
    ['common_mistakes'].forEach(f => { partial[f] = extractField(candidate, f, 'array'); });
    const filledCount = Object.values(partial).filter(v => v !== null).length;
    if (filledCount > 0) {
      partial._extraction_method = 'field_by_field_fallback';
      partial._fields_recovered  = filledCount;
      llmContent = partial;
      parseError += ` | fallback recovered ${filledCount} fields`;
    } else {
      llmContent = { parse_failed: true, raw_response: raw.substring(0, 3000), error: parseError };
    }
  }
} else {
  parseError = 'No JSON object found';
  llmContent  = { parse_failed: true, raw_response: raw.substring(0, 3000), error: parseError };
}

return [{
  json: {
    student_id:            upstream.student_id,
    gap:                   upstream.gap,
    overall_mastery_score: upstream.overall_mastery_score,
    llm_output:            llmContent,
    llm_parse_error:       parseError,
    llm_model:             'qwen2.5-coder:7b',
    llm_responded_at:      new Date().toISOString(),
    agent_retry_count:     upstream.agent_retry_count || 0,
    agent_state:           upstream.agent_state || 'initial',
    llm_prompt:            upstream.llm_prompt,
    slm_prompt:            upstream.slm_prompt
  }
}];

// ── QUALITY REVIEW AGENT V17 ─────────────────────────────────────────
// This is the core agentic component: it evaluates LLM output quality,
// decides autonomously whether to ACCEPT, RETRY with refined prompt,
// or PATCH missing fields — without human intervention.

const item = $input.first().json;
const llm  = item.llm_output || {};
const gap  = item.gap || {};
const retryCount = item.agent_retry_count || 0;
const MAX_RETRIES = 2;

// ── Quality scoring criteria ──────────────────────────────────────────
const checks = {
  has_title:          !!llm.page_title,
  has_introduction:   !!(llm.introduction?.what_is_it),
  has_concept:        !!(llm.concept_explained?.core_definition),
  has_syntax:         !!(llm.syntax_reference?.basic_syntax),
  has_examples:       !!(llm.examples?.example_1?.code),
  has_steps:          Array.isArray(llm.step_by_step_guide?.steps) && llm.step_by_step_guide.steps.length >= 3,
  has_debug_exercise: !!(llm.debugging_exercise?.broken_code),
  has_mistakes:       Array.isArray(llm.common_mistakes) && llm.common_mistakes.length >= 2,
  no_parse_fail:      !llm.parse_failed,
  no_empty_codes:     !!(llm.examples?.example_1?.code?.length > 50)
};

const passedChecks = Object.values(checks).filter(Boolean).length;
const totalChecks  = Object.keys(checks).length;
const qualityScore = Math.round((passedChecks / totalChecks) * 100);

// ── Agent Decision Logic ──────────────────────────────────────────────
let agentDecision;
let refinedPromptAddition = '';

if (qualityScore >= 80) {
  // High quality — accept and proceed
  agentDecision = 'ACCEPT';
} else if (retryCount < MAX_RETRIES) {
  // Subpar quality — agent decides to retry with targeted refinement
  agentDecision = 'RETRY';

  // Agent intelligently identifies WHICH fields are missing and refines the prompt
  const missing = Object.entries(checks).filter(([k,v]) => !v).map(([k]) => k);
  refinedPromptAddition = `

⚠️ QUALITY AGENT FEEDBACK (Retry ${retryCount + 1}/${MAX_RETRIES}):
The previous response was incomplete. You MUST include these missing sections:
${missing.map(m => `- ${m.replace(/_/g,' ')}`).join('\n')}

For debugging_exercise: include broken_code (15+ lines with // BUG) and solution_code.
For common_mistakes: include at least 3 objects with bad_code and good_code.
For examples.example_1.code: write a FULL runnable Java class, minimum 15 lines.
Quality score was ${qualityScore}/100. Target is 80+. Be thorough and complete.`;
} else {
  // Max retries exhausted — accept whatever we have with patch flag
  agentDecision = 'ACCEPT_WITH_PATCH';
}

// ── Patch missing fields with intelligent defaults ────────────────────
if (agentDecision === 'ACCEPT_WITH_PATCH') {
  const topic = gap.topic || 'Java Concept';
  if (!llm.page_title) llm.page_title = `Java ${topic} - MENTORA Tutorial`;
  if (!llm.introduction) llm.introduction = { what_is_it: `${topic} is an important Java concept.`, why_learn_it: 'Understanding this concept is essential for Java development.', prerequisite_note: 'Basic Java knowledge required.' };
  if (!llm.quick_reference) llm.quick_reference = { cheat_sheet: `Quick reference for ${topic}: review the examples above.`, key_terms: `${topic}: The main concept covered in this lesson.` };
  if (!llm.connections) llm.connections = { builds_on: 'Prerequisites apply here.', unlocks: 'This enables advanced Java topics.', real_world: `${topic} is used extensively in Java applications.` };
}

console.log(`[Quality Agent] Student: ${item.student_id} | Topic: ${gap.topic} | Score: ${qualityScore}/100 | Decision: ${agentDecision} | Retry: ${retryCount}`);

return [{
  json: {
    ...item,
    llm_output:              agentDecision === 'RETRY' ? item.llm_output : llm,
    agent_decision:          agentDecision,
    agent_quality_score:     qualityScore,
    agent_quality_checks:    checks,
    agent_retry_count:       retryCount,
    agent_refined_prompt:    agentDecision === 'RETRY' ? (item.llm_prompt + refinedPromptAddition) : item.llm_prompt,
    agent_decision_reason:   `Quality score ${qualityScore}/100 (${passedChecks}/${totalChecks} checks passed)`,
    agent_evaluated_at:      new Date().toISOString()
  }
}];

// ── ADAPTIVE RETRY AGENT V17 ─────────────────────────────────────────
// Prepares the refined prompt for the retry LLM call.
// Increments retry counter and updates state for traceability.

const item = $input.first().json;

console.log(`[Retry Agent] Preparing retry ${(item.agent_retry_count||0)+1} for student ${item.student_id}, topic: ${item.gap?.topic}`);

return [{
  json: {
    ...item,
    llm_prompt:        item.agent_refined_prompt,
    agent_retry_count: (item.agent_retry_count || 0) + 1,
    agent_state:       'retry_' + ((item.agent_retry_count || 0) + 1),
    retry_initiated_at: new Date().toISOString()
  }
}];

// Parse the retry LLM response — same robust logic as the primary parser
const item     = $input.first().json;
const upstream = $('Adaptive Retry Agent').first().json;

