    else if (s[i] === '}') { depth--; if (depth === 0) return s.substring(start, i+1); }
  }
  const last = s.lastIndexOf('}');
  return last > start ? s.substring(start, last+1) : null;
}

let llmContent = null, parseError = null;
const candidate = findOutermostObject(stripFences(raw));
if (candidate) {
  try { llmContent = JSON.parse(candidate); }
  catch(e) { parseError = e.message; llmContent = { parse_failed: true, raw_response: raw.substring(0,2000), error: parseError }; }
} else {
  parseError = 'No JSON object found in retry response';
  llmContent  = { parse_failed: true, raw_response: raw.substring(0,2000), error: parseError };
}

return [{
  json: {
    ...upstream,
    llm_output:       llmContent,
    llm_parse_error:  parseError,
    llm_model:        'qwen2.5-coder:7b',
    llm_responded_at: new Date().toISOString()
  }
}];

const item     = $input.first().json;
const upstream = $('Prompt Construction Module').first().json;

const raw = (item.message?.content || item.response || '').trim();

function stripFences(s) { return s.replace(/^```json\s*/gi,'').replace(/^```\s*/gi,'').replace(/\s*```$/gi,'').trim(); }
function findOutermostObject(s) {
  const start = s.indexOf('{'); if (start === -1) return null;
  let depth = 0;
  for (let i = start; i < s.length; i++) {
    if (s[i] === '{') depth++; else if (s[i] === '}') { depth--; if (depth === 0) return s.substring(start, i+1); }
  }
  const last = s.lastIndexOf('}');
  return last > start ? s.substring(start, last+1) : null;
}

function extractField(s, fieldName, type) {
  if (type === 'string') {
    const re = new RegExp('"' + fieldName + '"\\s*:\\s*"((?:[^"\\\\]|\\\\.)*)"', 's');
    const m = s.match(re);
    return m ? m[1].replace(/\\n/g,'\n').replace(/\\"/g,'"') : null;
  }
  const b = type==='array'?'[':'{';
  const cb = type==='array'?']':'}';
  const re = new RegExp('"'+fieldName+'"\\s*:\\s*(\\'+b+')');
  const m = re.exec(s); if (!m) return null;
  let start = m.index+m[0].length-1, depth=0;
  for (let i=start;i<s.length;i++) {
    if (s[i]===b) depth++; else if (s[i]===cb) { depth--; if (depth===0) { try { return JSON.parse(s.substring(start,i+1)); } catch(e) { return null; } } }
  }
  return null;
}

let slmContent = null, parseError = null;
const candidate = findOutermostObject(stripFences(raw));
if (candidate) {
  try { slmContent = JSON.parse(candidate); }
  catch(e) {
