  slmContent  = { parse_failed: true, raw_response: raw.substring(0,2000), error: parseError };
}

return [{ json: { student_id: upstream.student_id, gap: upstream.gap, slm_output: slmContent, slm_parse_error: parseError, slm_model: 'qwen2.5-coder:7b', slm_responded_at: new Date().toISOString() } }];

// ── CONTENT VALIDATION AGENT V17 ─────────────────────────────────────
// Agentic validator that checks SLM (assessment) output quality.
// Autonomously patches missing quiz/practice fields with sensible defaults
// rather than failing silently.

const item = $input.first().json;
const slm  = item.slm_output || {};
const gap  = item.gap || {};
const topic = gap.topic || 'Java Concept';
const level = gap.difficulty_level || 'beginner';

const validationChecks = {
  has_quiz:              Array.isArray(slm.quiz) && slm.quiz.length >= 3,
  has_quiz_explanations: Array.isArray(slm.quiz) && slm.quiz.every(q => !!q.explanation),
  has_concept_summary:   !!(slm.concept_summary && slm.concept_summary.length > 50),
  has_practice:          !!(slm.practice_challenge?.problem_statement),
  has_starter_code:      !!(slm.practice_challenge?.starter_code),
  has_self_check:        Array.isArray(slm.self_check?.can_you) && slm.self_check.can_you.length >= 3,
  no_parse_fail:         !slm.parse_failed
};

const validScore = Math.round((Object.values(validationChecks).filter(Boolean).length / Object.keys(validationChecks).length) * 100);

// Agent auto-patches missing assessment content
const patched = { ...slm };

if (!validationChecks.has_quiz || !Array.isArray(patched.quiz)) {
  patched.quiz = [
    { question_number: 1, type: 'conceptual', question: `What is the primary purpose of ${topic} in Java?`, options: ['A) Memory management', 'B) Code organization and reusability', 'C) Exception handling', 'D) Thread synchronization'], correct: 'B', explanation: `${topic} is primarily used for code organization and reusability in Java.`, misconception_targeted: 'general concept', difficulty: level },
    { question_number: 2, type: 'conceptual', question: `When should you use ${topic} in Java?`, options: ['A) Always', 'B) Never', 'C) When solving problems that have self-similar sub-problems', 'D) Only in legacy code'], correct: 'C', explanation: `Use ${topic} when the problem can be broken down into smaller, similar sub-problems.`, misconception_targeted: 'use case', difficulty: level },
    { question_number: 3, type: 'conceptual', question: `Which of the following is most important when implementing ${topic}?`, options: ['A) Performance only', 'B) A proper base/termination case', 'C) Using global variables', 'D) Avoiding return values'], correct: 'B', explanation: `A proper termination condition is critical to prevent infinite loops in ${topic}.`, misconception_targeted: 'base case', difficulty: level }
  ];
  patched._quiz_patched = true;
}

if (!validationChecks.has_concept_summary) {
  patched.concept_summary = `WHAT IS ${topic.toUpperCase()}?\nA fundamental Java programming concept that enables modular, reusable code.\n\nKEY RULE:\nAlways define a clear termination condition.\n\nREMEMBER:\n• Break the problem into smaller sub-problems\n• Ensure every path has a return value\n• Test with small inputs first`;
  patched._summary_patched = true;
}

if (!validationChecks.has_practice) {
  patched.practice_challenge = { title: `Practice: ${topic}`, difficulty: level, time_estimate: '20 minutes', problem_statement: `Implement a ${topic} solution in Java. Your solution should correctly handle edge cases and produce the expected output.`, requirements: ['Correct base case handling', 'Proper recursive structure', 'Input validation'], starter_code: `public class Practice${topic.replace(/\s/g,'')} {\n    public static void main(String[] args) {\n        // TODO: Test your implementation\n    }\n    // TODO: Implement your solution\n}`, example_input: '5', expected_output: 'Solution output for input 5', bonus: `Extend your solution to handle ${gap.related_topics?.[0] || 'additional edge cases'}.` };
  patched._practice_patched = true;
}

if (!validationChecks.has_self_check) {
  patched.self_check = { can_you: [`Can you explain ${topic} to someone new?`, `Can you write a ${topic} solution without help?`, `Can you trace execution step by step?`, `Can you spot a bug in a broken implementation?`, `Can you explain when to use ${topic} vs alternatives?`], if_stuck: `Review the concept_explanation and examples again. Try tracing through a simple example by hand before coding.` };
  patched._self_check_patched = true;
}

console.log(`[Content Validation Agent] Student: ${item.student_id} | Topic: ${topic} | Score: ${validScore}/100 | Patches: ${JSON.stringify(Object.keys(patched).filter(k=>k.includes('_patched')))}`);

return [{
  json: {
    ...item,
    slm_output:                      patched,
    content_validation_score:        validScore,
    content_validation_checks:       validationChecks,
    content_validation_agent_ran_at: new Date().toISOString()
  }
}];

const all     = $input.all();
const llmItem = all.find(i => i.json.llm_output !== undefined)?.json ?? {};
const slmItem = all.find(i => i.json.slm_output !== undefined)?.json ?? {};

const studentId = llmItem.student_id || slmItem.student_id || 'unknown';
const gap       = llmItem.gap        || slmItem.gap        || {};
const llm       = llmItem.llm_output || {};
const slm       = slmItem.slm_output || {};

const materialId  = `${studentId}_${gap.topic_id || 'unknown'}_${Date.now()}`;
const generatedAt = new Date().toISOString();

const structuredMaterial = {
  material_id:   materialId,
  student_id:    studentId,
  topic:         gap.topic,
  topic_id:      gap.topic_id,
  gap_type:      gap.gap_type,
  difficulty_level: gap.difficulty_level,
  generated_at:  generatedAt,

  generation_models: {
    llm: llmItem.llm_model || 'qwen2.5-coder:7b',
    slm: slmItem.slm_model || 'qwen2.5-coder:7b'
  },

  // ── Full W3Schools-style lesson (from LLM) ───────────────────────────
  lesson: {
    page_title:            llm.page_title            || null,
    introduction:          llm.introduction          || null,
    concept_explained:     llm.concept_explained     || null,
    syntax_reference:      llm.syntax_reference      || null,
    examples:              llm.examples              || null,
    step_by_step_guide:    llm.step_by_step_guide    || null,
    common_mistakes:       llm.common_mistakes        || [],
    debugging_exercise:    llm.debugging_exercise    || null,
    quick_reference:       llm.quick_reference       || null,
    connections:           llm.connections           || null
  },

  // ── Assessment content (from SLM + Content Validation Agent) ────────
  assessment: {
    quiz:               slm.quiz             || [],
    concept_summary:    slm.concept_summary  || null,
    practice_challenge: slm.practice_challenge || null,
    self_check:         slm.self_check       || null
  },

  // ── Personalisation metadata ─────────────────────────────────────────
  personalisation: {
    misconceptions_targeted: gap.misconceptions      || [],
    error_patterns:          gap.error_patterns      || {},
    evidence_summary:        gap.evidence_summary    || null,
    prerequisite_topics:     gap.prerequisite_topics || [],
    related_topics:          gap.related_topics      || []
  },

  // ── Study plan ───────────────────────────────────────────────────────
  study_plan: {
    estimated_minutes:   gap.estimated_time_minutes || 60,
    learning_objectives: gap.learning_objectives    || [],
    suggested_sequence: [
      { step: 1, activity: 'Read introduction and concept_explained', duration_min: 10, focus: 'Build intuition and correct misconceptions' },
      { step: 2, activity: 'Follow step_by_step_guide', duration_min: 15, focus: 'Understand the design process' },
      { step: 3, activity: 'Study examples (all 3)', duration_min: 10, focus: 'See correct and incorrect patterns' },
      { step: 4, activity: 'Complete debugging_exercise', duration_min: 15, focus: 'Apply understanding to find bugs' },
      { step: 5, activity: 'Answer quiz questions', duration_min: 10, focus: 'Verify conceptual understanding' },
      { step: 6, activity: 'Attempt practice_challenge', duration_min: null, focus: 'Independent application' }
    ],
    prerequisite_review: gap.prerequisite_topics || []
  },

  // ── Agentic AI metadata ──────────────────────────────────────────────
  agentic_metadata: {
    quality_review_agent: {
      decision:      llmItem.agent_decision          || 'ACCEPT',
      quality_score: llmItem.agent_quality_score     || null,
      checks:        llmItem.agent_quality_checks    || {},
      retry_count:   llmItem.agent_retry_count       || 0,
      final_state:   llmItem.agent_state             || 'initial',
      evaluated_at:  llmItem.agent_evaluated_at      || null,
      reason:        llmItem.agent_decision_reason   || null
    },
    content_validation_agent: {
      validation_score:  slmItem.content_validation_score   || null,
      checks:            slmItem.content_validation_checks  || {},
      patches_applied:   Object.keys(slmItem.slm_output || {}).filter(k => k.includes('_patched')),
      validated_at:      slmItem.content_validation_agent_ran_at || null
    }
  },

  // ── Quality metadata ─────────────────────────────────────────────────
  quality_flags: {
    llm_parse_failed:          !!llmItem.llm_parse_error,
    slm_parse_failed:          !!slmItem.slm_parse_error,
    agent_retried:             (llmItem.agent_retry_count || 0) > 0,
    agent_patched_llm:         llmItem.agent_decision === 'ACCEPT_WITH_PATCH',
    agent_patched_slm:         Object.keys(slmItem.slm_output || {}).some(k => k.includes('_patched')),
    needs_review:              !!(llmItem.llm_parse_error || slmItem.slm_parse_error || llm.parse_failed || slm.parse_failed),
    overall_quality_score:     Math.round(((llmItem.agent_quality_score || 0) + (slmItem.content_validation_score || 0)) / 2),
    content_completeness: {
      has_introduction:        !!(llm.introduction?.what_is_it),
      has_concept_explained:   !!(llm.concept_explained?.core_definition),
      has_syntax:              !!(llm.syntax_reference?.basic_syntax),
      has_examples:            !!(llm.examples?.example_1?.code),
      has_step_guide:          Array.isArray(llm.step_by_step_guide?.steps),
      has_debug_exercise:      !!(llm.debugging_exercise?.broken_code),
      has_quiz:                (slm.quiz || []).length >= 3,
      has_practice:            !!(slm.practice_challenge?.problem_statement),
      has_self_check:          Array.isArray(slm.self_check?.can_you)
    }
  }
};

const comparisonLog = {
  log_id:                     `comp_${materialId}`,
  student_id:                 studentId,
  topic:                      gap.topic,
  llm_model:                  llmItem.llm_model,
  slm_model:                  slmItem.slm_model,
  llm_responded_at:           llmItem.llm_responded_at,
  slm_responded_at:           slmItem.slm_responded_at,
  llm_parse_error:            llmItem.llm_parse_error  || null,
  slm_parse_error:            slmItem.slm_parse_error  || null,
  agent_quality_score:        llmItem.agent_quality_score,
  content_validation_score:   slmItem.content_validation_score,
  agent_retry_count:          llmItem.agent_retry_count,
  timestamp:                  generatedAt
};

return [{ json: { structured_material: structuredMaterial, comparison_log: comparisonLog } }];

const errorData = $input.first().json;
const errorLog = {
  error_id:      `err_${Date.now()}`,
  student_id:    errorData.student_id || 'unknown',
  error_message: errorData.error?.message || 'Unknown error',
  error_node:    errorData.execution?.lastNode || 'unknown',
  timestamp:     new Date().toISOString(),
  raw_payload:   JSON.stringify(errorData).substring(0, 500)
};
console.error('Pipeline error:', JSON.stringify(errorLog));
return [{ json: errorLog }];

// Initialize the sequential loop state.
// Attach current_index=0 so the first gap is processed first.
const item = $json;

if (!Array.isArray(item.processed_gaps) || item.processed_gaps.length === 0) {
  throw new Error('No processed_gaps found. Check Profile Processing Module.');
}

return [{
  json: {
    ...item,
    current_index: 0,
    total_gaps: item.processed_gaps.length
  }
}];

// Extract the gap at current_index from processed_gaps.
// This is the single gap that will go through the full pipeline.
const item = $json;

const idx  = item.current_index;
const gap  = item.processed_gaps[idx];

if (!gap) throw new Error(`Get Current Gap: no gap at index ${idx}`);

console.log(`[Loop] Processing gap ${idx + 1}/${item.total_gaps}: ${gap.topic}`);

return [{
  json: {
    // Carry loop state forward so Increment Index can use it
    processed_gaps:        item.processed_gaps,
    current_index:         idx,
    total_gaps:            item.total_gaps,
    student_id:            gap.student_id,
    overall_mastery_score: gap.overall_mastery_score,
    gap:                   gap
  }
}];

// Called after MongoDB stores the current gap's material.
// Increments current_index and carries processed_gaps forward.
// The Check If Done node decides whether to loop or stop.

// Get the loop state from Get Current Gap (carried through the whole pipeline)
const loopState = $('Get Current Gap').first().json;

const nextIndex = (loopState.current_index || 0) + 1;

console.log(`[Loop] Gap ${loopState.current_index + 1}/${loopState.total_gaps} done. Next index: ${nextIndex}`);

return [{
  json: {
    processed_gaps: loopState.processed_gaps,
    current_index:  nextIndex,
    total_gaps:     loopState.total_gaps,
    student_id:     loopState.student_id
  }
}];

